const BUNDLE_ID = "hydra-reward-hydrafang";
const ITEM_NAME = "Возмездие Гидриного Клыка";
const JOURNAL_NAME = "Награда: Возмездие Гидриного Клыка";
const ITEM_FOLDER_NAME = "Награды гидры";
const JOURNAL_FOLDER_NAME = "Награды гидры";
let IMG = "icons/weapons/swords/sword-broad-serrated-green.webp";

function htmlDescription() {
  return `
<div class="ai-patcher-item-description">
  <p><em>Этот почерневший клинок был вытянут из последней дымящейся раны гидры. Семь малых голов обвивают его гарду: каждая застыла на полушипении, каждая всё ещё влажна от изумрудного яда.</em></p>

  <h3>Редкое магическое оружие</h3>
  <p><strong>Оружие (длинный меч), редкое, требует настройки</strong></p>

  <p>Вы получаете бонус +1 к броскам атаки и урона этим магическим оружием. При попадании клинок наносит дополнительно <strong>1d6 урона кислотой</strong>, когда одна из резных голов гидры впивается в открытую рану.</p>

  <h3>Многошеяя гарда</h3>
  <p>Пока вы настроены на это оружие и носите или держите его, чешуйчатая гарда гидры защитно смыкается вокруг вашей руки. Вы получаете бонус +1 к КД и сопротивление урону ядом.</p>

  <h3>Яд отсечённой головы</h3>
  <p>У оружия есть <strong>3 заряда</strong>, и оно восстанавливает все потраченные заряды, когда вы заканчиваете продолжительный отдых. Бонусным действием вы можете потратить 1 заряд и заставить одно видимое вами существо в пределах 30 футов совершить <strong>спасбросок Телосложения Сл 15</strong>. При провале цель получает <strong>3d6 урона ядом и 3d6 урона кислотой</strong> и становится отравленной до конца вашего следующего хода. При успехе цель получает половину этого урона и не становится отравленной.</p>

</div>`;
}

function chatDescription() {
  return "Предсмертные судороги гидры всё ещё живут в клинке: длинный меч +1, +1d6 кислотой при попадании, 3 заряда для ядовитого выброса со Сл 15.";
}

async function getOrCreateFolder(name, type) {
  let folder = game.folders.find((entry) => entry.type === type && entry.name === name);
  if (folder) return folder;
  return Folder.create({ name, type });
}

function baseDamage(number, denomination, types, bonus = "") {
  return {
    number,
    denomination,
    bonus,
    types,
    custom: {
      enabled: false,
      formula: ""
    },
    scaling: {
      mode: "",
      number: null,
      formula: ""
    }
  };
}

function buildActivities(itemData, poisonedEffectId) {
  const attackSource = foundry.utils.deepClone(itemData);
  attackSource.system.actionType = "mwak";
  attackSource.system.activation = { type: "action", cost: 1, condition: "" };
  attackSource.system.attack = { bonus: "", flat: false };
  attackSource.system.ability = "";
  attackSource.system.critical = { threshold: null, damage: "" };
  attackSource.system.damage.parts = [["1d6", "acid"]];
  CONFIG.DND5E.activityTypes.attack.documentClass.createInitialActivity(attackSource, { offset: 0 });

  const attack = Object.values(attackSource.system.activities).find((activity) => activity.type === "attack");
  attack.name = "Удар гидриного клыка";
  attack.img = IMG;
  attack.description.chatFlavor = "Клинок кусает, и семь влажных от кислоты пастей терзают рану.";

  const saveSource = foundry.utils.deepClone(itemData);
  saveSource.effects = itemData.effects.filter((effect) => effect._id === poisonedEffectId);
  saveSource.system.actionType = "save";
  saveSource.system.activation = { type: "bonus", cost: 1, condition: "После того как яд гидры выступает на лезвии." };
  saveSource.system.consume = { type: "charges", target: "", amount: 1, scale: false };
  saveSource.system.damage.parts = [["3d6", "poison"], ["3d6", "acid"]];
  saveSource.system.duration = { value: null, units: "inst" };
  saveSource.system.range = { value: 30, units: "ft" };
  saveSource.system.save = { ability: "con", dc: 15, scaling: "flat" };
  saveSource.system.target = { value: 1, type: "creature", units: "", prompt: true };
  CONFIG.DND5E.activityTypes.save.documentClass.createInitialActivity(saveSource, { offset: 1 });

  const venom = Object.values(saveSource.system.activities).find((activity) => activity.type === "save");
  venom.name = "Яд отсечённой головы";
  venom.img = IMG;
  venom.description.chatFlavor = "Призрачная голова гидры вырывается из гарды и выплёвывает изумрудный яд.";

  itemData.system.activities = {
    [attack._id]: attack,
    [venom._id]: venom
  };
}

function buildItemData(itemFolderId) {
  const carrierEffectId = foundry.utils.randomID();
  const poisonedEffectId = foundry.utils.randomID();

  const itemData = {
    name: ITEM_NAME,
    type: "weapon",
    img: IMG,
    folder: itemFolderId,
    ownership: {
      default: CONST.DOCUMENT_OWNERSHIP_LEVELS.OBSERVER
    },
    flags: {
      "ai-patcher": {
        bundleId: BUNDLE_ID,
        role: "hydra-reward"
      },
      dnd5e: {
        sourceId: `ai-patcher.${BUNDLE_ID}`
      }
    },
    system: {
      description: {
        value: htmlDescription(),
        chat: chatDescription()
      },
      identified: true,
      unidentified: {
        name: "Чёрный клинок, влажный от яда",
        description: "Чёрно-зелёный клинок из кости гидры, яда и старого боевого железа."
      },
      source: {
        custom: "Награда за гидру"
      },
      quantity: 1,
      weight: {
        value: 3,
        units: "lb"
      },
      price: {
        value: 2500,
        denomination: "gp"
      },
      rarity: "rare",
      attunement: "required",
      attuned: false,
      equipped: false,
      type: {
        value: "martialM",
        baseItem: "longsword"
      },
      properties: ["mgc", "ver"],
      magicalBonus: "1",
      mastery: "sap",
      proficient: null,
      range: {
        value: null,
        long: null,
        reach: 5,
        units: "ft"
      },
      damage: {
        base: baseDamage(1, 8, ["slashing"]),
        versatile: baseDamage(1, 10, ["slashing"])
      },
      uses: {
        spent: 0,
        max: "3",
        recovery: [
          {
            period: "lr",
            type: "recoverAll",
            formula: ""
          }
        ]
      },
      activities: {}
    },
    effects: [
      {
        _id: carrierEffectId,
        name: "Многошеяя гарда",
        img: IMG,
        origin: "",
        transfer: true,
        disabled: false,
        changes: [
          {
            key: "system.attributes.ac.bonus",
            mode: CONST.ACTIVE_EFFECT_MODES.ADD,
            value: "1",
            priority: 20
          },
          {
            key: "system.traits.dr.value",
            mode: CONST.ACTIVE_EFFECT_MODES.ADD,
            value: "poison",
            priority: 20
          }
        ],
        description: "Пока владелец настроен на оружие и использует его, чешуйчатая гарда гидры даёт +1 к КД и сопротивление урону ядом.",
        flags: {
          dnd5e: {
            type: "base"
          }
        }
      },
      {
        _id: poisonedEffectId,
        name: "Яд гидры",
        img: "icons/svg/poison.svg",
        origin: "",
        transfer: false,
        disabled: false,
        statuses: ["poisoned"],
        duration: {
          rounds: 1,
          turns: 1
        },
        changes: [],
        description: "Отравлен ядом отсечённой головы гидры до конца следующего хода владельца клинка.",
        flags: {
          dnd5e: {
            type: "base"
          }
        }
      }
    ]
  };

  buildActivities(itemData, poisonedEffectId);
  return itemData;
}

function journalContent(item) {
  const itemLink = item ? `@UUID[${item.uuid}]{${ITEM_NAME}}` : `<strong>${ITEM_NAME}</strong>`;
  return `
<div class="ai-patcher-reward">
  <p><img src="${IMG}" style="border:0; max-width:420px; width:100%; display:block; margin:0 auto 1rem;"></p>
  <h2>${ITEM_NAME}</h2>
  <p><em>Когда последняя голова гидры перестала двигаться, один клык не остыл вместе с телом. Он продолжал расти, продолжал раздваиваться, продолжал помнить каждую шею, которую отсекли.</em></p>
  <p>Предмет-награда создан здесь: ${itemLink}</p>
  <ul>
    <li><strong>Редкий магический длинный меч</strong>, требует настройки.</li>
    <li><strong>Автоматизированная атака:</strong> магическое оружие +1, базовый рубящий урон, дополнительный урон кислотой 1d6.</li>
    <li><strong>Автоматизированные заряды:</strong> 3 заряда за продолжительный отдых для свойства «Яд отсечённой головы».</li>
    <li><strong>Автоматизированный спасбросок:</strong> спасбросок Телосложения Сл 15, урон ядом и кислотой, с накладываемым эффектом отравления.</li>
    <li><strong>Переносимый эффект:</strong> +1 к КД и сопротивление яду, пока предмет активен как магический предмет владельца.</li>
  </ul>
</div>`;
}

async function createOrUpdateJournal(journalFolderId, item, dryRun) {
  const existing = game.journal.find((entry) => entry.getFlag("ai-patcher", "bundleId") === BUNDLE_ID || entry.name === JOURNAL_NAME);
  if (dryRun) {
    return {
      action: existing ? "update" : "create",
      type: "JournalEntry",
      name: JOURNAL_NAME
    };
  }

  const data = {
    name: JOURNAL_NAME,
    folder: journalFolderId,
    flags: {
      "ai-patcher": {
        bundleId: BUNDLE_ID,
        role: "hydra-reward-handout"
      }
    },
    pages: [
      {
        name: ITEM_NAME,
        type: "text",
        text: {
          format: CONST.JOURNAL_ENTRY_PAGE_FORMATS.HTML,
          content: journalContent(item)
        }
      }
    ]
  };

  if (existing) return existing.update(data);
  return JournalEntry.create(data);
}

export default async function patch({ dryRun, log, bundle }) {
  IMG = bundle?.assets?.["assets/hydrafang-reprisal.png"] ?? IMG;
  if (game.system.id !== "dnd5e") {
    throw new Error("«Возмездие Гидриного Клыка» создано для системы dnd5e.");
  }

  log(`Подготовка: ${ITEM_NAME}`);

  const existing = game.items.find((item) => item.getFlag("ai-patcher", "bundleId") === BUNDLE_ID || item.name === ITEM_NAME);

  if (dryRun) {
    const itemFolder = game.folders.find((entry) => entry.type === "Item" && entry.name === ITEM_FOLDER_NAME);
    const journalFolder = game.folders.find((entry) => entry.type === "JournalEntry" && entry.name === JOURNAL_FOLDER_NAME);
    const itemData = buildItemData(itemFolder?.id ?? null);
    return {
      wouldCreateOrUpdate: {
        item: {
          action: existing ? "update" : "create",
          name: ITEM_NAME,
          type: "weapon",
          rarity: itemData.system.rarity,
          attunement: itemData.system.attunement,
          activities: Object.values(itemData.system.activities).map((activity) => ({
            name: activity.name,
            type: activity.type
          })),
          effects: itemData.effects.map((effect) => effect.name)
        },
        journal: await createOrUpdateJournal(journalFolder?.id ?? null, null, true)
      }
    };
  }

  const itemFolder = await getOrCreateFolder(ITEM_FOLDER_NAME, "Item");
  const journalFolder = await getOrCreateFolder(JOURNAL_FOLDER_NAME, "JournalEntry");
  const itemData = buildItemData(itemFolder.id);
  const item = existing ? await existing.update(itemData) : await Item.create(itemData);
  const journal = await createOrUpdateJournal(journalFolder.id, item, false);

  log(`${ITEM_NAME} готов в справочнике предметов.`);
  return {
    item: {
      id: item.id,
      uuid: item.uuid,
      name: item.name
    },
    journal: {
      id: journal.id,
      uuid: journal.uuid,
      name: journal.name
    }
  };
}
